<script setup lang="ts">import{ref,computed}from'vue';import{Volume2,CheckCircle2,ChevronRight}from'lucide-vue-next';import type{Lesson}from'@/types/course';const props=defineProps<{lesson:Lesson}>();const answers=ref<Record<string,number>>({});const completed=ref<string[]>([]);const progress=computed(()=>props.lesson.blocks.length?Math.round(completed.value.length/props.lesson.blocks.length*100):0);function complete(id:string){if(!completed.value.includes(id))completed.value.push(id)}function answer(id:string,index:number){answers.value[id]=index;complete(id)}</script><template><div class="player"><p class="eyebrow">Урок · {{lesson.duration}} минут</p><h1>{{lesson.title}}</h1><article v-for="block in lesson.blocks" :key="block.id" :class="['player-block',block.type]" @mouseenter="block.type!=='single_choice'&&complete(block.id)"><h2 v-if="block.type==='heading'">{{block.content}}</h2><p v-else-if="block.type==='text'">{{block.content}}</p><aside v-else-if="block.type==='callout'"><b>{{block.title}}</b><p>{{block.content}}</p></aside><button v-else-if="block.type==='audio'" class="audio" @click="complete(block.id)"><Volume2/>Воспроизвести аудио<span>0:42</span></button><div v-else><h3>{{block.content}}</h3><button v-for="(option,index) in block.options" :key="option" :class="['answer',answers[block.id]===index&&'chosen',answers[block.id]!==undefined&&index===block.correctOption&&'correct']" @click="answer(block.id,index)">{{option}}<CheckCircle2 v-if="answers[block.id]!==undefined&&index===block.correctOption"/></button></div></article><div class="player-footer"><span>{{completed.length}} из {{lesson.blocks.length}} блоков</span><button class="primary" :disabled="progress<100">Завершить урок <ChevronRight/></button></div></div></template>